import{_ as a,o as t,c as i,ae as s}from"./chunks/framework.BD9pLfSD.js";const h=JSON.parse('{"title":"Branch Plan: Infra + Observability (Helius + Receipts)","description":"","frontmatter":{},"headers":[],"relativePath":"docs/plans/branch_infra_observability.md","filePath":"docs/plans/branch_infra_observability.md"}'),l={name:"docs/plans/branch_infra_observability.md"};function n(o,e,r,p,c,u){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="branch-plan-infra-observability-helius-receipts" tabindex="-1">Branch Plan: Infra + Observability (Helius + Receipts) <a class="header-anchor" href="#branch-plan-infra-observability-helius-receipts" aria-label="Permalink to &quot;Branch Plan: Infra + Observability (Helius + Receipts)&quot;">​</a></h1><h2 id="objective" tabindex="-1">Objective <a class="header-anchor" href="#objective" aria-label="Permalink to &quot;Objective&quot;">​</a></h2><p>Provide reliable infrastructure (Helius RPC/webhooks) and receipts (Light or mock) for the demo, aligned with the SDK/MCP payment flow and the on-chain gateway/receipts path, with Hub as the command plane for observability.</p><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><ul><li>Helius RPC integration and priority fee config (smoke test + env guidance).</li><li>Optional Helius webhooks for observability.</li><li>Receipts layer using Light or a mock compatible interface, including CPI wiring.</li><li>SDK receipts adapter + MCP list/latest alignment.</li><li>Demo scripts for devnet/localnet runs (e2e + receipt builder).</li><li>Localnet infra scripts for Light validator when devnet is unstable.</li><li>Hub wiring to surface gateway/payment/receipt state for demo observability (merchant views as extensions of the Hub).</li></ul><h2 id="out-of-scope" tabindex="-1">Out of Scope <a class="header-anchor" href="#out-of-scope" aria-label="Permalink to &quot;Out of Scope&quot;">​</a></h2><ul><li>Payment rail logic details (handled in Payments branch).</li><li>New Hub UI features beyond wiring observability into existing flows.</li></ul><h2 id="milestones" tabindex="-1">Milestones <a class="header-anchor" href="#milestones" aria-label="Permalink to &quot;Milestones&quot;">​</a></h2><ul><li>[x] 1) Helius RPC path validated with a simple tx (smoke test).</li><li>[x] 2) Receipt write path implemented (Light or mock) and surfaced to SDK receipts module.</li><li>[x] 3) Demo script produces logs + receipts via gateway -&gt; payment -&gt; receipt (SDK/MCP).</li><li>[x] 4) <strong>Bonus:</strong> Unified Listener with SQLite persistence implemented (<code>mcp/src/listener.ts</code>).</li></ul><h2 id="deliverables" tabindex="-1">Deliverables <a class="header-anchor" href="#deliverables" aria-label="Permalink to &quot;Deliverables&quot;">​</a></h2><ul><li>[x] Config guidance for Helius endpoints + smoke test script.</li><li>[x] Receipt adapter + CPI builder script.</li><li>[x] MCP/SDK receipt integration notes (list/latest).</li><li>[x] Demo script for e2e flow (Smoke Listener).</li><li>[ ] Hub panel that surfaces live receipts, balances, and recent payment status (merchant-focused).</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>Helius API key / endpoint.</li><li>Light RPC endpoints (compression/prover) or localnet validator.</li><li>On-chain gateway/receipts programs deployed.</li><li>MCP/SDK receipt interface availability.</li></ul><h2 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">​</a></h2><ul><li>Light infra instability or RPC rate limits.</li><li>Webhook setup friction.</li><li>Receipt interface drift between SDK/MCP and on-chain programs.</li></ul><h2 id="fallback" tabindex="-1">Fallback <a class="header-anchor" href="#fallback" aria-label="Permalink to &quot;Fallback&quot;">​</a></h2><ul><li>Mock receipts stored in standard accounts + local logs.</li><li>Expose receipts via SDK list/latest with mocked data if Light is unstable.</li><li>Use localnet Light validator scripts for demos.</li></ul><h2 id="decisions" tabindex="-1">Decisions <a class="header-anchor" href="#decisions" aria-label="Permalink to &quot;Decisions&quot;">​</a></h2><ul><li>Demo target: localnet first; devnet only if time allows.</li><li>Merchant hub: treated as an extension of the main Hub UI (merchant-focused panels).</li></ul><h2 id="breakpoints" tabindex="-1">Breakpoints <a class="header-anchor" href="#breakpoints" aria-label="Permalink to &quot;Breakpoints&quot;">​</a></h2><ul><li>BP1: Helius RPC tx confirmed.</li><li>BP2: Receipt written or mocked and visible via SDK receipts.</li><li>BP3: Demo script produces observable output.</li></ul><h2 id="todos-reproducible" tabindex="-1">TODOs (Reproducible) <a class="header-anchor" href="#todos-reproducible" aria-label="Permalink to &quot;TODOs (Reproducible)&quot;">​</a></h2><ul><li>Standardize RPC/Helius/Light env vars across SDK/MCP/Hub and document defaults.</li><li>Run Helius smoke test and capture a reference signature + RPC URL.</li><li>Validate Light receipts with <code>sdk/scripts/build_receipt_light.ts</code> (devnet) and store a sample payload.</li><li>Run <code>sdk/scripts/demo_e2e.ts</code> and verify SDK receipts list/latest output.</li><li>Wire Hub to MCP/SDK state for receipts, balances, and latest payment status.</li><li>Validate Hub rendering with latest receipts and a recent payment.</li><li>Prepare localnet Light fallback (scripts + minimal runbook).</li><li>Document the demo execution order (step-by-step, reproducible).</li></ul><h2 id="_7-day-execution-checklist-localnet-demo" tabindex="-1">7-Day Execution Checklist (Localnet Demo) <a class="header-anchor" href="#_7-day-execution-checklist-localnet-demo" aria-label="Permalink to &quot;7-Day Execution Checklist (Localnet Demo)&quot;">​</a></h2><p>Day 1: Hub + MCP wiring</p><ul><li>Run MCP in HTTP mode and register agent in Hub (<code>/tool</code> endpoint).</li><li>Verify Hub observability panel shows balance/receipts via MCP tools.</li><li>Consolidate env vars for MCP/SDK/Hub (<code>XB77_*</code>, <code>MCP_HTTP_PORT</code>).</li></ul><p>Day 2: Receipts pipeline</p><ul><li>Run <code>sdk/scripts/build_receipt_light.ts</code> against localnet Light.</li><li>Validate receipt payload + accounts JSON output.</li><li>Confirm SDK receipt list/latest returns consistent data.</li></ul><p>Day 3: E2E demo (localnet)</p><ul><li>Run <code>sdk/scripts/demo_e2e.ts</code> and capture output logs.</li><li>Confirm gateway -&gt; receipt path emits expected receipts.</li><li>Capture a “golden run” transcript for demo.</li></ul><p>Day 4: Merchant Hub extension</p><ul><li>Add/confirm merchant-focused labels and sections in Hub panel.</li><li>Ensure merchant flow maps to receipts and balance state.</li></ul><p>Day 5: Infra hardening</p><ul><li>Run Helius smoke test (for optional devnet path).</li><li>Validate localnet Light fallback scripts and document runbook.</li></ul><p>Day 6: Demo rehearsal</p><ul><li>Full dry run: Hub + MCP + demo flow.</li><li>Record common failure cases and quick fixes.</li></ul><p>Day 7: Final polish</p><ul><li>Freeze env + scripts + runbook.</li><li>Final demo run and screenshots/logs.</li></ul><h2 id="next-session-runbook-mock-receipts-hub-observability" tabindex="-1">Next Session Runbook (Mock Receipts + Hub Observability) <a class="header-anchor" href="#next-session-runbook-mock-receipts-hub-observability" aria-label="Permalink to &quot;Next Session Runbook (Mock Receipts + Hub Observability)&quot;">​</a></h2><p>Goal: reproduce the demo without touching on-chain programs.</p><p>Pre-reqs:</p><ul><li>Use a local keypair at <code>.localnet/payer.json</code>.</li><li>Run MCP in offline mode with static balances.</li></ul><p>Step 1: Start MCP HTTP (offline)</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cd mcp</span></span>
<span class="line"><span>XB77_KEYPAIR_PATH=../.localnet/payer.json \\</span></span>
<span class="line"><span>XB77_OFFLINE=true \\</span></span>
<span class="line"><span>XB77_BALANCES_JSON=&#39;{&quot;USD1&quot;:2500}&#39; \\</span></span>
<span class="line"><span>MCP_HTTP_PORT=7001 \\</span></span>
<span class="line"><span>bun run src/http.ts</span></span></code></pre></div><p>Step 2: Start Hub</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bun --hot hub/index.ts</span></span></code></pre></div><p>Step 3: Register agent in Hub</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl -s -X POST http://localhost:7777/register \\</span></span>
<span class="line"><span>  -H &#39;content-type: application/json&#39; \\</span></span>
<span class="line"><span>  -d &#39;{&quot;agent_id&quot;:&quot;agent-alpha&quot;,&quot;mcp_url&quot;:&quot;http://localhost:7001/tool&quot;,&quot;transport&quot;:&quot;http&quot;,&quot;capabilities&quot;:[&quot;agent.state.get&quot;,&quot;agent.receipts.list&quot;,&quot;agent.pay&quot;],&quot;pubkey&quot;:&quot;&lt;PAYER_PUBKEY&gt;&quot;}&#39;</span></span></code></pre></div><p>Step 4: Simulate payment (offline)</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl -s -X POST http://localhost:7777/agent/agent-alpha/tool \\</span></span>
<span class="line"><span>  -H &#39;content-type: application/json&#39; \\</span></span>
<span class="line"><span>  -d &#39;{&quot;name&quot;:&quot;agent.pay&quot;,&quot;arguments&quot;:{&quot;recipient&quot;:&quot;merchant-001&quot;,&quot;amount&quot;:42,&quot;token&quot;:&quot;USD1&quot;,&quot;type&quot;:&quot;internal&quot;}}&#39;</span></span></code></pre></div><p>Step 5: Verify receipts + state</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl -s -X POST http://localhost:7777/agent/agent-alpha/tool \\</span></span>
<span class="line"><span>  -H &#39;content-type: application/json&#39; \\</span></span>
<span class="line"><span>  -d &#39;{&quot;name&quot;:&quot;agent.receipts.list&quot;,&quot;arguments&quot;:{&quot;limit&quot;:5}}&#39;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>curl -s -X POST http://localhost:7777/agent/agent-alpha/tool \\</span></span>
<span class="line"><span>  -H &#39;content-type: application/json&#39; \\</span></span>
<span class="line"><span>  -d &#39;{&quot;name&quot;:&quot;agent.state.get&quot;,&quot;arguments&quot;:{&quot;token&quot;:&quot;USD1&quot;}}&#39;</span></span></code></pre></div><p>Stop all:</p><ul><li>Ctrl+C both MCP and Hub terminals.</li></ul>`,54)])])}const b=a(l,[["render",n]]);export{h as __pageData,b as default};
